#!/usr/bin/perl

use strict;
use warnings;
use CGI;
use CGI::Carp qw(fatalsToBrowser);
use File::Basename;

my $q = CGI->new;

my $log_dir = '/var/log'; # Define your log directory
my $filename_param = $q->param('logfile');

# Print HTTP header
print $q->header('text/html');

# Basic HTML structure
print << "HTML_START";
