if (!$filename_param) {
    print "<p>Please specify a log file using the 'logfile' query parameter.</p>";
    print "<p>Example: <a href=\"?logfile=syslog\">?logfile=syslog</a></p>";
    print "<p>Available log files (first level):</p>";
    print "<ul>";
    opendir(my $dh, $log_dir) or die "Cannot open directory $log_dir: $!";
    while (my $entry = readdir($dh)) {
        next if ($entry eq '.' || $entry eq '..');
        my $full_path = File::Spec->catfile($log_dir, $entry);
        if (-f $full_path && !-d $full_path) { # Ensure it's a file, not a directory
            print "<li><a href=\"?logfile=$entry\">$entry</a></li>";
        }
    }
    closedir($dh);
    print "</ul>";
} else {
    # Sanitize filename: only allow base name, no path traversal
    my $filename = basename($filename_param);
    if ($filename ne $filename_param) {
        print "<p class=\"error\">Invalid filename provided. Path traversal attempts are blocked.</p>";
        print "<p>Please use just the filename without any path components.</p>";
        $filename = ''; # Clear filename to prevent further processing
    }

    if ($filename) {
        my $filepath = "$log_dir/$filename";

        # Check if the file exists and is a regular file
        if (!-e $filepath) {
            print "<p class=\"error\">Error: Log file '$filename' not found.</p>";
        } elsif (!-f $filepath) {
            print "<p class=\"error\">Error: '$filename' is not a regular file.</p>";
        } else {
            print "<h2>Displaying Log: $filename</h2>";
            print "<pre>";
            if (open(my $fh, "<", $filepath)) {
                while (my $line = <$fh>) {
                    print $q->escapeHTML($line); # Escape HTML to prevent XSS
                }
                close($fh);
            } else {
                print "<p class=\"error\">Error opening file '$filepath': $!</p>";
            }
            print "</pre>";
        }
    }
}

